# Memory Leaking with `Box::leak` in Rust

## Basic Implementation

```rust
use std::collections::HashMap;
use std::sync::OnceLock;

/// Demonstrates Box::leak for creating a 'static string from runtime data
fn create_static_str(s: String) -> &'static str {
    Box::leak(s.into_boxed_str())
}

/// Demonstrates Box::leak for a static configuration
fn create_static_config(config: HashMap<String, String>) -> &'static HashMap<String, String> {
    Box::leak(Box::new(config))
}

fn main() {
    // Example 1: Static string from runtime data
    let dynamic_string = format!("Hello, {}!", "world");
    let static_str: &'static str = create_static_str(dynamic_string);
    println!("Static str: {}", static_str);

    // Example 2: Global configuration loaded once
    let mut config = HashMap::new();
    config.insert("host".to_string(), "localhost".to_string());
    config.insert("port".to_string(), "8080".to_string());

    let static_config: &'static HashMap<String, String> = create_static_config(config);
    println!("Config host: {}", static_config["host"]);
}
```

